"use strict";(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[948],{40948:function(n){n.exports=JSON.parse('{"slug":"doc-su6ryo","title":"手撕代码题","description":"","date":null,"tags":[],"category":"LLM","categoryId":"llm","content":"# 手撕代码题\\n\\n> **更新日期**: 2026-03-13\\n> **版本**: v1.0\\n> **难度**: 中级\\n> **预计阅读时间**: 60 分钟\\n\\n---\\n\\n## 目录\\n\\n1. [Transformer 组件](#transformer-组件)\\n2. [注意力机制](#注意力机制)\\n3. [位置编码](#位置编码)\\n4. [推理优化](#推理优化)\\n5. [训练技巧](#训练技巧)\\n6. [完整模型](#完整模型)\\n\\n---\\n\\n## Transformer 组件\\n\\n### 1. Layer Normalization\\n\\n```python\\nclass LayerNorm(nn.Module):\\n    \\"\\"\\"层归一化\\"\\"\\"\\n\\n    def __init__(self, d_model, eps=1e-6):\\n        super().__init__()\\n        self.eps = eps\\n        self.gamma = nn.Parameter(torch.ones(d_model))\\n        self.beta = nn.Parameter(torch.zeros(d_model))\\n\\n    def forward(self, x):\\n        \\"\\"\\"\\n        x: [batch, seq_len, d_model]\\n        \\"\\"\\"\\n        # 计算均值和方差\\n        mean = x.mean(dim=-1, keepdim=True)\\n        var = x.var(dim=-1, keepdim=True, unbiased=False)\\n\\n        # 归一化\\n        x_norm = (x - mean) / torch.sqrt(var + self.eps)\\n\\n        # 缩放和平移\\n        return self.gamma * x_norm + self.beta\\n```\\n\\n### 2. Feed Forward Network\\n\\n```python\\nclass FeedForward(nn.Module):\\n    \\"\\"\\"前馈网络\\"\\"\\"\\n\\n    def __init__(self, d_model, d_ff, dropout=0.1):\\n        super().__init__()\\n        self.linear1 = nn.Linear(d_model, d_ff)\\n        self.linear2 = nn.Linear(d_ff, d_model)\\n        self.dropout = nn.Dropout(dropout)\\n        self.activation = nn.GELU()\\n\\n    def forward(self, x):\\n        \\"\\"\\"\\n        x: [batch, seq_len, d_model]\\n        \\"\\"\\"\\n        x = self.linear1(x)\\n        x = self.activation(x)\\n        x = self.dropout(x)\\n        x = self.linear2(x)\\n        return x\\n```\\n\\n### 3. 残差连接\\n\\n```python\\nclass ResidualConnection(nn.Module):\\n    \\"\\"\\"残差连接 + LayerNorm\\"\\"\\"\\n\\n    def __init__(self, d_model, dropout=0.1):\\n        super().__init__()\\n        self.norm = LayerNorm(d_model)\\n        self.dropout = nn.Dropout(dropout)\\n\\n    def forward(self, x, sublayer):\\n        \\"\\"\\"\\n        x: 输入\\n        sublayer: 子层函数\\n        \\"\\"\\"\\n        # Pre-LN: 先归一化再经过子层\\n        return x + self.dropout(sublayer(self.norm(x)))\\n```\\n\\n---\\n\\n## 注意力机制\\n\\n### 1. Scaled Dot-Product Attention\\n\\n```python\\ndef attention(Q, K, V, mask=None, dropout=None):\\n    \\"\\"\\"\\n    缩放点积注意力\\n\\n    Q, K, V: [batch, heads, seq_len, d_k]\\n    mask: [batch, 1, seq_len, seq_len] 或广播形式\\n    \\"\\"\\"\\n    d_k = Q.size(-1)\\n\\n    # 计算注意力分数\\n    scores = torch.matmul(Q, K.transpose(-2, -1))  # [batch, heads, seq, seq]\\n    scores = scores / math.sqrt(d_k)\\n\\n    # 应用 mask\\n    if mask is not None:\\n        scores = scores.masked_fill(mask == 0, -1e9)\\n\\n    # Softmax\\n    attn_weights = F.softmax(scores, dim=-1)\\n\\n    # Dropout\\n    if dropout is not None:\\n        attn_weights = dropout(attn_weights)\\n\\n    # 加权求和\\n    output = torch.matmul(attn_weights, V)  # [batch, heads, seq, d_k]\\n\\n    return output, attn_weights\\n```\\n\\n### 2. Multi-Head Attention\\n\\n```python\\nclass MultiHeadAttention(nn.Module):\\n    \\"\\"\\"多头注意力\\"\\"\\"\\n\\n    def __init__(self, d_model, num_heads, dropout=0.1):\\n        super().__init__()\\n        assert d_model % num_heads == 0\\n\\n        self.d_model = d_model\\n        self.num_heads = num_heads\\n        self.d_k = d_model // num_heads\\n\\n        # Q, K, V 投影\\n        self.W_q = nn.Linear(d_model, d_model)\\n        self.W_k = nn.Linear(d_model, d_model)\\n        self.W_v = nn.Linear(d_model, d_model)\\n        self.W_o = nn.Linear(d_model, d_model)\\n\\n        self.dropout = nn.Dropout(dropout)\\n\\n    def split_heads(self, x):\\n        \\"\\"\\"\\n        x: [batch, seq_len, d_model]\\n        输出: [batch, heads, seq_len, d_k]\\n        \\"\\"\\"\\n        batch_size, seq_len, _ = x.size()\\n        x = x.view(batch_size, seq_len, self.num_heads, self.d_k)\\n        return x.transpose(1, 2)\\n\\n    def combine_heads(self, x):\\n        \\"\\"\\"\\n        x: [batch, heads, seq_len, d_k]\\n        输出: [batch, seq_len, d_model]\\n        \\"\\"\\"\\n        batch_size, _, seq_len, _ = x.size()\\n        x = x.transpose(1, 2).contiguous()\\n        return x.view(batch_size, seq_len, self.d_model)\\n\\n    def forward(self, query, key, value, mask=None):\\n        \\"\\"\\"\\n        query, key, value: [batch, seq_len, d_model]\\n        mask: [batch, 1, seq_len, seq_len]\\n        \\"\\"\\"\\n        # 投影并分头\\n        Q = self.split_heads(self.W_q(query))\\n        K = self.split_heads(self.W_k(key))\\n        V = self.split_heads(self.W_v(value))\\n\\n        # 注意力计算\\n        attn_output, attn_weights = attention(\\n            Q, K, V, mask, self.dropout\\n        )\\n\\n        # 合并头并输出投影\\n        output = self.W_o(self.combine_heads(attn_output))\\n\\n        return output, attn_weights\\n```\\n\\n### 3. 因果掩码 (Causal Mask)\\n\\n```python\\ndef create_causal_mask(seq_len):\\n    \\"\\"\\"\\n    创建因果掩码 (上三角为0)\\n    输出: [seq_len, seq_len]\\n    \\"\\"\\"\\n    mask = torch.triu(torch.ones(seq_len, seq_len), diagonal=1)\\n    mask = mask.masked_fill(mask == 1, float(\'-inf\'))\\n    return mask\\n\\n# 或使用 bool mask\\ndef create_causal_mask_bool(seq_len):\\n    \\"\\"\\"创建布尔因果掩码\\"\\"\\"\\n    mask = torch.tril(torch.ones(seq_len, seq_len))\\n    return mask.bool()\\n```\\n\\n---\\n\\n## 位置编码\\n\\n### 1. 正弦位置编码\\n\\n```python\\nclass SinusoidalPositionalEncoding(nn.Module):\\n    \\"\\"\\"正弦位置编码\\"\\"\\"\\n\\n    def __init__(self, d_model, max_len=5000, dropout=0.1):\\n        super().__init__()\\n        self.dropout = nn.Dropout(dropout)\\n\\n        # 计算位置编码\\n        pe = torch.zeros(max_len, d_model)\\n        position = torch.arange(0, max_len, dtype=torch.float).unsqueeze(1)\\n\\n        div_term = torch.exp(\\n            torch.arange(0, d_model, 2).float() *\\n            (-math.log(10000.0) / d_model)\\n        )\\n\\n        pe[:, 0::2] = torch.sin(position * div_term)\\n        pe[:, 1::2] = torch.cos(position * div_term)\\n\\n        pe = pe.unsqueeze(0)  # [1, max_len, d_model]\\n        self.register_buffer(\'pe\', pe)\\n\\n    def forward(self, x):\\n        \\"\\"\\"\\n        x: [batch, seq_len, d_model]\\n        \\"\\"\\"\\n        x = x + self.pe[:, :x.size(1)]\\n        return self.dropout(x)\\n```\\n\\n### 2. RoPE (旋转位置编码)\\n\\n```python\\ndef precompute_freqs_cis(dim: int, end: int, theta: float = 10000.0):\\n    \\"\\"\\"\\n    预计算旋转频率\\n\\n    dim: 维度\\n    end: 最大序列长度\\n    \\"\\"\\"\\n    freqs = 1.0 / (theta ** (torch.arange(0, dim, 2).float() / dim))\\n    t = torch.arange(end)\\n    freqs = torch.outer(t, freqs)  # [end, dim//2]\\n    freqs_cis = torch.polar(torch.ones_like(freqs), freqs)  # 复数形式\\n    return freqs_cis\\n\\n\\ndef apply_rotary_emb(xq, xk, freqs_cis):\\n    \\"\\"\\"\\n    应用旋转位置编码\\n\\n    xq, xk: [batch, heads, seq_len, head_dim]\\n    freqs_cis: [seq_len, head_dim//2] 复数\\n    \\"\\"\\"\\n    # 转换为复数\\n    def reshape_for_broadcast(x):\\n        # [batch, heads, seq_len, head_dim] -> [batch, heads, seq_len, head_dim//2, 2]\\n        x = x.float().reshape(*x.shape[:-1], -1, 2)\\n        return torch.view_as_complex(x)\\n\\n    xq_ = reshape_for_broadcast(xq)\\n    xk_ = reshape_for_broadcast(xk)\\n\\n    # 对齐维度\\n    freqs_cis = freqs_cis.unsqueeze(0).unsqueeze(0)  # [1, 1, seq_len, head_dim//2]\\n\\n    # 旋转\\n    xq_out = torch.view_as_real(xq_ * freqs_cis).flatten(3)\\n    xk_out = torch.view_as_real(xk_ * freqs_cis).flatten(3)\\n\\n    return xq_out.type_as(xq), xk_out.type_as(xk)\\n```\\n\\n---\\n\\n## 推理优化\\n\\n### 1. KV Cache\\n\\n```python\\nclass KVCache:\\n    \\"\\"\\"KV Cache 管理\\"\\"\\"\\n\\n    def __init__(self, num_layers, num_heads, head_dim, max_seq_len):\\n        self.num_layers = num_layers\\n        self.k_cache = [\\n            torch.zeros(1, num_heads, max_seq_len, head_dim)\\n            for _ in range(num_layers)\\n        ]\\n        self.v_cache = [\\n            torch.zeros(1, num_heads, max_seq_len, head_dim)\\n            for _ in range(num_layers)\\n        ]\\n        self.current_len = 0\\n\\n    def update(self, layer_idx, new_k, new_v):\\n        \\"\\"\\"\\n        更新 cache\\n        new_k, new_v: [batch, heads, new_len, head_dim]\\n        \\"\\"\\"\\n        batch_size, _, new_len, _ = new_k.shape\\n        start = self.current_len\\n        end = start + new_len\\n\\n        self.k_cache[layer_idx][:, :, start:end] = new_k\\n        self.v_cache[layer_idx][:, :, start:end] = new_v\\n\\n        self.current_len = end\\n\\n    def get(self, layer_idx):\\n        \\"\\"\\"获取当前 cache\\"\\"\\"\\n        return (\\n            self.k_cache[layer_idx][:, :, :self.current_len],\\n            self.v_cache[layer_idx][:, :, :self.current_len]\\n        )\\n\\n\\ndef attention_with_cache(Q, K, V, k_cache, v_cache, layer_idx, mask=None):\\n    \\"\\"\\"使用 KV Cache 的注意力\\"\\"\\"\\n    # 更新 cache\\n    k_cache.update(layer_idx, K, V)\\n\\n    # 获取完整 K, V\\n    full_k, full_v = k_cache.get(layer_idx)\\n\\n    # 计算注意力 (只计算新 token 的输出)\\n    scores = torch.matmul(Q, full_k.transpose(-2, -1)) / math.sqrt(Q.size(-1))\\n\\n    if mask is not None:\\n        scores = scores.masked_fill(mask == 0, -1e9)\\n\\n    attn = F.softmax(scores, dim=-1)\\n    output = torch.matmul(attn, full_v)\\n\\n    return output\\n```\\n\\n### 2. GQA (分组查询注意力)\\n\\n```python\\nclass GroupedQueryAttention(nn.Module):\\n    \\"\\"\\"分组查询注意力\\"\\"\\"\\n\\n    def __init__(self, d_model, num_heads, num_kv_heads, dropout=0.1):\\n        super().__init__()\\n        self.num_heads = num_heads\\n        self.num_kv_heads = num_kv_heads\\n        self.head_dim = d_model // num_heads\\n        self.num_groups = num_heads // num_kv_heads\\n\\n        # Q: num_heads, K/V: num_kv_heads\\n        self.W_q = nn.Linear(d_model, num_heads * self.head_dim)\\n        self.W_k = nn.Linear(d_model, num_kv_heads * self.head_dim)\\n        self.W_v = nn.Linear(d_model, num_kv_heads * self.head_dim)\\n        self.W_o = nn.Linear(d_model, d_model)\\n\\n    def forward(self, x, mask=None):\\n        batch, seq_len, _ = x.shape\\n\\n        # 投影\\n        Q = self.W_q(x).view(batch, seq_len, self.num_heads, self.head_dim)\\n        K = self.W_k(x).view(batch, seq_len, self.num_kv_heads, self.head_dim)\\n        V = self.W_v(x).view(batch, seq_len, self.num_kv_heads, self.head_dim)\\n\\n        # 扩展 K, V 以匹配 Q 的头数\\n        # [batch, seq, num_kv_heads, head_dim] -> [batch, seq, num_heads, head_dim]\\n        K = K.repeat_interleave(self.num_groups, dim=2)\\n        V = V.repeat_interleave(self.num_groups, dim=2)\\n\\n        # 转置为 [batch, heads, seq, head_dim]\\n        Q = Q.transpose(1, 2)\\n        K = K.transpose(1, 2)\\n        V = V.transpose(1, 2)\\n\\n        # 注意力计算\\n        scores = torch.matmul(Q, K.transpose(-2, -1)) / math.sqrt(self.head_dim)\\n        if mask is not None:\\n            scores = scores.masked_fill(mask == 0, -1e9)\\n\\n        attn = F.softmax(scores, dim=-1)\\n        output = torch.matmul(attn, V)\\n\\n        # 合并头\\n        output = output.transpose(1, 2).contiguous().view(batch, seq_len, -1)\\n        return self.W_o(output)\\n```\\n\\n---\\n\\n## 训练技巧\\n\\n### 1. LoRA\\n\\n```python\\nclass LoRALayer(nn.Module):\\n    \\"\\"\\"LoRA 层\\"\\"\\"\\n\\n    def __init__(self, in_features, out_features, rank=8, alpha=16):\\n        super().__init__()\\n        self.rank = rank\\n        self.alpha = alpha\\n        self.scaling = alpha / rank\\n\\n        self.lora_A = nn.Parameter(torch.zeros(in_features, rank))\\n        self.lora_B = nn.Parameter(torch.zeros(rank, out_features))\\n\\n        nn.init.kaiming_uniform_(self.lora_A)\\n        nn.init.zeros_(self.lora_B)\\n\\n    def forward(self, x):\\n        \\"\\"\\"x @ A @ B * scaling\\"\\"\\"\\n        return (x @ self.lora_A @ self.lora_B) * self.scaling\\n\\n\\nclass LinearWithLoRA(nn.Module):\\n    def __init__(self, base_layer, rank=8, alpha=16):\\n        super().__init__()\\n        self.base_layer = base_layer\\n        self.lora = LoRALayer(\\n            base_layer.in_features,\\n            base_layer.out_features,\\n            rank, alpha\\n        )\\n\\n        # 冻结原权重\\n        for param in self.base_layer.parameters():\\n            param.requires_grad = False\\n\\n    def forward(self, x):\\n        return self.base_layer(x) + self.lora(x)\\n```\\n\\n---\\n\\n## 完整模型\\n\\n### 极简 GPT\\n\\n```python\\nclass MiniGPT(nn.Module):\\n    \\"\\"\\"极简 GPT 实现\\"\\"\\"\\n\\n    def __init__(self, vocab_size, d_model=512, num_heads=8,\\n                 num_layers=6, d_ff=2048, max_len=512, dropout=0.1):\\n        super().__init__()\\n\\n        self.token_emb = nn.Embedding(vocab_size, d_model)\\n        self.pos_emb = SinusoidalPositionalEncoding(d_model, max_len, dropout)\\n\\n        self.layers = nn.ModuleList([\\n            TransformerBlock(d_model, num_heads, d_ff, dropout)\\n            for _ in range(num_layers)\\n        ])\\n\\n        self.norm = LayerNorm(d_model)\\n        self.output = nn.Linear(d_model, vocab_size)\\n\\n    def forward(self, x, mask=None):\\n        # Embedding\\n        x = self.token_emb(x)\\n        x = self.pos_emb(x)\\n\\n        # Transformer 层\\n        for layer in self.layers:\\n            x = layer(x, mask)\\n\\n        # 输出\\n        x = self.norm(x)\\n        return self.output(x)\\n\\n    def generate(self, prompt, max_new_tokens=100, temperature=1.0):\\n        \\"\\"\\"自回归生成\\"\\"\\"\\n        self.eval()\\n        generated = prompt\\n\\n        for _ in range(max_new_tokens):\\n            # 准备输入\\n            logits = self.forward(generated)\\n            logits = logits[:, -1, :] / temperature\\n\\n            # 采样\\n            probs = F.softmax(logits, dim=-1)\\n            next_token = torch.multinomial(probs, num_samples=1)\\n\\n            # 添加到序列\\n            generated = torch.cat([generated, next_token], dim=1)\\n\\n        return generated\\n","filePath":"面试专题/手撕代码题.md"}')}}]);